#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;
class Solution {
public:
    int maxGifts(int n, vector<int>& arr, int budget) {
        sort(arr.begin(), arr.end());
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (arr[i] <= budget) {
                count++;
                budget -= arr[i];
            }
            if (budget <= 0) break;
        }
        return count;
    }
};

